class Solution:
    def clumsy(self, n: int) -> int:
        if n <= 2:
            return n
        stack = [n]
        n -= 1
        ops = ['*', '/', '+', '-']
        op_idx = 0
        while n > 0:
            if ops[op_idx] == '*':
                stack[-1] *= n
            elif ops[op_idx] == '/':
                stack[-1] = int(stack[-1] / n)
            elif ops[op_idx] == '+':
                stack.append(n)
            else:
                stack.append(-n)
            n -= 1
            op_idx = (op_idx + 1) % 4
        return sum(stack)
```
